// Format any incoming alert into a clean Telegram message
const body = $input.first().json.body || $input.first().json;
const eventType = body.event_type || 'unknown';
const ts = new Date().toLocaleString('en-GB', { 
  timeZone: 'Europe/Berlin',
  day: '2-digit', month: 'short', year: 'numeric',
  hour: '2-digit', minute: '2-digit'
});

let emoji = '🔔';
let title = 'Alert';
let details = '';
let urgency = '⚪ Low';
let actionNeeded = 'Review when convenient.';

switch (eventType) {
  case 'new_lead':
    emoji = '🎯';
    title = 'New Lead';
    urgency = '🟡 Medium';
    actionNeeded = 'Review and follow up within 2 hours.';
    details = [
      `👤 Name: ${body.name || 'Unknown'}`,
      `📧 Email: ${body.email || 'Unknown'}`,
      `📍 Source: ${body.source || 'Unknown'}`,
      body.details ? `📝 Notes: ${body.details}` : ''
    ].filter(Boolean).join('\n');
    break;

  case 'payment_received':
    emoji = '💰';
    title = 'Payment Received';
    urgency = '🟢 Info';
    actionNeeded = 'No action needed — log for records.';
    details = [
      `👤 Client: ${body.customer_name || 'Unknown'}`,
      `💶 Amount: ${body.currency || 'EUR'} ${body.amount || '0.00'}`,
      `📦 Product: ${body.product || 'Unknown'}`,
    ].join('\n');
    break;

  case 'chatbot_escalation':
    emoji = '🆘';
    title = 'Chatbot Escalation — Human Needed';
    urgency = '🔴 Urgent';
    actionNeeded = 'Reply to customer within 30 minutes.';
    details = [
      `👤 Customer: ${body.customer_name || 'Unknown'}`,
      `📧 Email: ${body.email || 'Unknown'}`,
      `💬 Message: "${(body.message || '').slice(0, 200)}"`,
      `🆔 Session: ${body.session_id || 'N/A'}`
    ].join('\n');
    break;

  case 'invoice_overdue':
    emoji = '⚠️';
    title = 'Invoice Overdue';
    urgency = '🔴 Urgent';
    actionNeeded = 'Call or email client today.';
    details = [
      `👤 Client: ${body.client_name || 'Unknown'}`,
      `🧾 Invoice: ${body.invoice_id || 'Unknown'}`,
      `💶 Amount: €${body.amount || '0.00'}`,
      `📅 Days Overdue: ${body.days_overdue || '?'} days`
    ].join('\n');
    break;

  case 'workflow_error':
    emoji = '🚨';
    title = 'Workflow Error';
    urgency = '🔴 Critical';
    actionNeeded = 'Check n8n execution logs immediately.';
    details = [
      `⚙️ Workflow: ${body.workflow_name || 'Unknown'}`,
      `❌ Error: ${(body.error_message || 'Unknown error').slice(0, 200)}`,
      `🕐 Time: ${body.timestamp || ts}`
    ].join('\n');
    break;

  default:
    emoji = '📢';
    title = 'Business Alert';
    details = JSON.stringify(body, null, 2).slice(0, 500);
}

const message = [
  `${emoji} *${title}*`,
  `━━━━━━━━━━━━━━━━━━━━`,
  details,
  `━━━━━━━━━━━━━━━━━━━━`,
  `🕐 ${ts}`,
  `📊 Priority: ${urgency}`,
  `✅ Action: ${actionNeeded}`
].join('\n');

return [{ json: { message, event_type: eventType, timestamp: ts } }];

// Build daily digest from today's alert log
const items = $input.all();
const today = new Date().toDateString();

// Filter to today's alerts only
const todayAlerts = items.filter(item => {
  const ts = item.json.Timestamp || item.json.timestamp || '';
  try {
    return new Date(ts).toDateString() === today;
  } catch { return false; }
});

// Count by event type
const counts = {};
for (const alert of todayAlerts) {
  const type = alert.json.Event_Type || alert.json.event_type || 'unknown';
  counts[type] = (counts[type] || 0) + 1;
}

const countLines = Object.entries(counts).map(([type, count]) => {
  const emojis = {
    new_lead: '🎯',
    payment_received: '💰',
    chatbot_escalation: '🆘',
    invoice_overdue: '⚠️',
    workflow_error: '🚨'
  };
  const label = type.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase());
  return `${emojis[type] || '🔔'} ${label}: ${count}`;
});

const now = new Date().toLocaleDateString('en-GB', {
  weekday: 'long', day: '2-digit', month: 'short'
});

const message = todayAlerts.length > 0
  ? [
      `📊 *Daily Business Digest — ${now}*`,
      `━━━━━━━━━━━━━━━━━━━━`,
      `Total alerts today: *${todayAlerts.length}*`,
      '',
      ...countLines,
      `━━━━━━━━━━━━━━━━━━━━`,
      `✅ End of day summary complete. See you tomorrow!`
    ].join('\n')
  : `📊 *Daily Digest — ${now}*\n\n✅ Quiet day — no alerts fired today. All systems running smoothly.`;

return [{ json: { message, alert_count: todayAlerts.length } }];

const error = $input.first().json;
console.error('ME-10 Error:', JSON.stringify(error));
return [{ json: { error: true, message: error.message || 'Alert system error', timestamp: new Date().toISOString() } }];
